  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="z" computer="DESKTOP-LC5V468" date="2025.07.02 13'55'30" map_xs="128" map_ys="128" north_angle="-1789569707" extra_map_edge="1" tileset="arctic" environment="Arctic_Final" players="6" name="Ледник" id="Ледник" style="0" description="Эта местность сформирована множеством огромных ледников, покрывших горные хребты, древний водоем и подножья спящего вулкана. Недавно лед на склонах вулкана начал активно таять, обнажая арктические скалы. Однако температуры здесь остаются невероятно низкими, не позволяя расти даже самым мелким растениям. Все игроки начинают с удвоенным количеством ресурсов. &#xA; {— От Матвея Icpompeo Аль-Бороди.}" enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="0" elimination="1" allies="12" living_world_bird="18" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="0" num_special="0" num_villages_override="12-14" num_special_override="18-24">
